from microcoapy import CoapServer, Resource

class TempSensorResource(Resource):
    def __init__(self):
        super().__init__('/sensors/temp')
        self.temp_value = 22.5  # Example temperature value

    def observe(self, request):
        self.add_observer(request)

    def respond(self):
        return str(self.temp_value).encode()

    def put(self, request):
        self.temp_value = float(request.payload.decode())
        return self.respond()


class LightActuatorResource(Resource):
    def __init__(self):
        super().__init__('/actuators/light')
        self.light_status = 'off'  # Example light status

    def observe(self, request):
        self.add_observer(request)

    def respond(self):
        return self.light_status.encode()

    def put(self, request):
        self.light_status = request.payload.decode()
        return self.respond()


def main():
    server = CoapServer()
    temp_resource = TempSensorResource()
    light_resource = LightActuatorResource()
    
    server.add_resource(temp_resource)
    server.add_resource(light_resource)
    
    server.start()

if __name__ == '__main__':
    main()